import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Dashboard() {
    const [file, setFile] = useState(null);
    const [result, setResult] = useState([]);
    const [resumes, setResumes] = useState([]);

    const navigate = useNavigate();
    const token = localStorage.getItem("token");

    // 🔒 PROTECT PAGE
    if (!token) {
        navigate("/login");
    }

    const handleUpload = async () => {
        const formData = new FormData();
        formData.append("file", file);
        formData.append("name", "Test User");
        formData.append("email", "test@gmail.com");
        formData.append("skills", "java spring boot");
        formData.append("experience", 2);

        await axios.post(
            "http://localhost:8080/resumes/upload",
            formData,
            {
                headers: {
                    Authorization: `Bearer ${token}`,
                    "Content-Type": "multipart/form-data"
                }
            }
        );

        alert("Uploaded!");
    };

    const getMatches = async () => {
        const res = await axios.get(
            "http://localhost:8080/resumes/match?skill=java&experience=1",
            {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            }
        );

        setResult(res.data);
    };
    const getResumes = async () => {
        try {
            const res = await axios.get("http://localhost:8080/resumes", {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            });

            setResumes(res.data);
        } catch (err) {
            console.error(err);
            alert("Failed to fetch resumes");
        }
    };
    const deleteResume = async (id) => {
        try {
            await axios.delete(`http://localhost:8080/resumes/${id}`, {
                headers: {
                    Authorization: `Bearer ${token}`
                }
            });

            alert("Deleted successfully");

            // refresh list
            getResumes();

        } catch (err) {
            console.error(err);
            alert("Delete failed");
        }
    };


    const handleLogout = () => {
        localStorage.removeItem("token");
        navigate("/login");
    };

    return (

        <div style={{ padding: 20 }}>
            <h2>Dashboard</h2>

            <button onClick={handleLogout}>Logout</button>

            <br /><br />

            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />

            <button onClick={handleUpload}>Upload Resume</button>

            <br /><br />

            <button onClick={getMatches}>Find Matches</button>
            <button onClick={getResumes}>View My Resumes</button><div style={{ marginTop: 20 }}>
            <h3>My Resumes</h3>

            {resumes.length === 0 && <p>No resumes found</p>}

            {resumes.map((r) => (
                <div key={r.id} style={{
                    border: "1px solid #ccc",
                    padding: 10,
                    marginBottom: 10,
                    borderRadius: 8
                }}>
                    <h4>{r.name}</h4>
                    <p><b>Email:</b> {r.email}</p>
                    <p><b>Skills:</b> {r.skills}</p>
                    <p><b>Experience:</b> {r.experience} years</p>

                    <button onClick={() => deleteResume(r.id)}>
                        Delete
                    </button>
                </div>
            ))}
        </div>

            <ul>
                {result?.map((r, i) => (
                    <li key={i}>
                        {r?.summary?.name || "No Name"} - Score: {r?.score}
                    </li>
                ))}
            </ul>
        </div>
    );
}

export default Dashboard;
